import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { Supplier } from '../../core/models';

/** Supplier detail. service_agent wires ApiService.getSupplier(id). */
@Component({
  selector: 'app-supplier-detail',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './supplier-detail.component.html',
  styleUrl: './supplier-detail.component.css',
})
export class SupplierDetailComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);
  readonly supplier = signal<Supplier | null>({
    id: 's1',
    name: 'Globex Supply Co',
    email: 'sales@globex.example',
    phone: '+1 312 555 0110',
  });

  readonly canEdit = computed(() => this.auth.isPurchasing());
  id = '';

  constructor(public auth: AuthService, private route: ActivatedRoute) {}

  ngOnInit(): void {
    this.id = this.route.snapshot.paramMap.get('id') ?? '';
    // service_agent: this.supplier.set(await ApiService.getSupplier(this.id)).
  }
}
